import { useMemo } from 'react';
import { type ExtractState, type StoreApi, useStore } from 'zustand';

import {
  type RecentAndPinnedFiltersState,
  scopedRecentAndPinnedFiltersStores,
  createRecentAndPinnedFilterStore,
  voidStore,
} from '../../state/recent-pinned-store.js';

/**
 * Allows access to the namespaced store in order to share filters.
 */
export function useRecentAndPinnedFiltersStore<U>(
  selector: (state: ExtractState<StoreApi<RecentAndPinnedFiltersState>>) => U,
  name: string | null = null,
): U {
  const store = useMemo(() => {
    if (name === null) {
      return null;
    }

    let scopedStore = scopedRecentAndPinnedFiltersStores.get(name);
    if (scopedStore === undefined) {
      scopedStore = createRecentAndPinnedFilterStore();
      scopedRecentAndPinnedFiltersStores.set(name, scopedStore);
    }
    return scopedStore;
  }, [name]);

  return useStore(store ?? voidStore, selector);
}
